import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a single string
        StringBuilder raw = new StringBuilder();
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        // Convert escaped "\\n" sequences to real newlines
        String data = raw.toString().replace("\\n", "\n");
        Scanner sc = new Scanner(new StringReader(data));
        if (!sc.hasNextInt()) {
            return;
        }
        int T = sc.nextInt();
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            if (!sc.hasNext()) break; // id
            String id = sc.next();
            if (!sc.hasNext()) break; // first name
            String first = sc.next();
            if (!sc.hasNext()) break; // last name
            String last = sc.next();
            if (!sc.hasNext()) break; // email token
            String email = sc.next();
            int at = email.indexOf('@');
            if (at != -1) {
                String domain = email.substring(at + 1);
                if (domain.equals("gmail.com") || domain.equals("yahoo.com") || domain.equals("hotmail.com")) {
                    sb.append(id).append(' ').append(first).append(' ').append(last).append('\n');
                }
            }
        }
        System.out.print(sb.toString());
    }
}

